import sys
input = sys.stdin.readline

n = int(input())
a = list(map(int, input().split()))

def check(x):
    for i in range(n-1):
        if a[i] == a[i+1]:
            return True
        if a[i] > a[i+1]:
            if x == i:
                return True
    return False

for i in range(n):
    if check(i):
        print("YES")
        exit()
print("NO")
